class GameState:
    def __init__(self) -> None:
        self.lock = threading.Lock()
        self.server_name = "Example Game Server"
        self.map_name = "arena_01"
        self.mode = "deathmatch"
        self.max_players = 64
        self.tick = 0
        self.round = 1
        self.score_red = 0
        self.score_blue = 0
        self.start_time = time.time()
        self.players: List[Dict[str, Any]] = []
        self._populate_players()

    def _populate_players(self) -> None:
        names = [
            "Alpha", "Bravo", "Charlie", "Delta", "Echo", "Foxtrot", "Ghost", "Hunter",
            "Iris", "Jester", "Kilo", "Lancer", "Mantis", "Nova", "Orion", "Phantom",
            "Quark", "Raven", "Specter", "Titan", "Umbra", "Viper", "Warden", "Zephyr"
        ]
        count = 24
        for i in range(count):
            self.players.append({
                "id": i + 1,
                "name": f"{random.choice(names)}_{i+1}",
                "team": "red" if i % 2 == 0 else "blue",
                "score": random.randint(0, 50),
                "ping": random.randint(20, 120),
                "connected_seconds": random.randint(30, 7200),
                "alive": random.choice([True, False]),
                "x": round(random.uniform(-1000, 1000), 2),
                "y": round(random.uniform(-1000, 1000), 2),
                "z": round(random.uniform(0, 250), 2),
            })

    def update_loop(self, stop_event: threading.Event) -> None:
        while not stop_event.is_set():
            time.sleep(1.0)
            with self.lock:
                self.tick += 60
                if random.random() < 0.2:
                    self.score_red += random.randint(0, 2)
