class UDPGameServer:
    def __init__(self, host: str, port: int, state: GameState) -> None:
        self.host = host
        self.port = port
        self.state = state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)
        self.stop_event = threading.Event()

    def serve_forever(self) -> None:
        while not self.stop_event.is_set():
            try:
                data, addr = self.sock.recvfrom(65535)
            except socket.timeout:
                continue
            except OSError:
                break
            threading.Thread(target=self.handle_packet, args=(data, addr), daemon=True).start()

    def shutdown(self) -> None:
        self.stop_event.set()
        try:
            self.sock.close()
        except OSError:
            pass

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        if not data:
            return
        request = data.strip().decode("utf-8", errors="ignore").lower()
        if request in ("status", "getstatus", "query", "fullstatus"):
            payload = self.build_status_payload()
            self.send_large_response(addr, payload)
        elif request in ("ping", "getinfo", "info"):
            info = {
                "server_name": self.state.server_name,
                "map_name": self.state.map_name,
                "mode": self.state.mode,
                "num_players": len(self.state.players),
                "max_players": self.state.max_players,
            }
            self.sock.sendto(json.dumps(info, separators=(",", ":")).encode("utf-8"), addr)
        else:
            self.sock.sendto(b'{"error":"unknown_query"}', addr)

    def build_status_payload(self) -> bytes:
        snapshot = self.state.snapshot()
        return json.dumps(snapshot, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    def send_large_response(self, addr: Tuple[str, int], payload: bytes) -> None:
        max_chunk = 1200
        total = (len(payload) + max_chunk - 1) // max_chunk
        if total <= 1:
            self.sock.sendto(payload, addr)
            return
        message_id = random.randint(0, 0xFFFFFFFF)
        for index in range(total):
            chunk = payload[index * max_chunk:(index + 1) * max_chunk]
            header = struct.pack("!4sIHH", b"STAT", message_id, index, total)
            self.sock.sendto(header + chunk, addr)
            time.sleep(0.001)


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=27015)
    args = parser.parse_args()

    state = GameState()
    server = UDPGameServer(args.host, args.port, state)

    updater_stop = threading.Event()
    updater_thread = threading.Thread(target=state.update_loop, args=(updater_stop,), daemon=True)
    updater_thread.start()

    def _shutdown(*_: Any) -> None:
        updater_stop.set()
        server.shutdown()

    signal.signal(signal.SIGINT, _shutdown)
    signal.signal(signal.SIGTERM, _shutdown)

    try:
        server.serve_forever()
    finally:
        updater_stop.set()
        server.shutdown()


if __name__ == "__main__":
    main()